import{_ as t,c as i,a as s,o as p}from"./app-CEcM0piI.js";const n={};function d(a,e){return p(),i("div",null,e[0]||(e[0]=[s(`<p>Item Views 组件是用于显示和编辑大量数据的强大工具集。这些组件允许你以表格、列表、树状等方式呈现数据，并提供了丰富的功能和灵活性。 Item View组件都继承自QAbstractItemModel 见的 Qt Item Views 组件：</p><ol><li>QTableView：QTableView 是用于显示表格数据的组件。它提供了类似于电子表格的界面，支持排序、过滤、编辑等功能。</li><li>QListView：QListView 是用于显示列表数据的组件。它以垂直或水平的方式显示项目，并可通过设置不同的视图模式进行定制。</li><li>QTreeView：QTreeView 是用于显示树状数据的组件。它以层次结构的方式显示数据，并支持展开和折叠节点、排序、过滤等功能。</li><li>QTableWidget：QTableWidget 是 QTableView 的子类，它提供了一个方便的方式来显示和编辑简单的表格数据。相比于 QTableView，QTableWidget 更易于使用，但功能相对较少。</li><li>QTreeWidget：QTreeWidget 是 QTreeView 的子类，它提供了一个方便的方式来显示和编辑简单的树状数据。类似于 QTableWidget，QTreeWidget 更易于使用，但功能相对较少。</li><li>QStandardItemModel：QStandardItemModel 是一个可用于提供数据给 Item Views 组件的模型类。它提供了灵活的接口来管理和操作数据，包括插入、删除、修改等操作。</li></ol><h3 id="常见接口" tabindex="-1"><a class="header-anchor" href="#常见接口"><span>常见接口</span></a></h3><p><strong>1.QAbstractItemModel：</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>rowCount(): 返回模型中的行数。</span></span>
<span class="line"><span>columnCount(): 返回模型中的列数。</span></span>
<span class="line"><span>data(): 返回给定索引处的数据。</span></span>
<span class="line"><span>setData(): 设置给定索引处的数据。</span></span>
<span class="line"><span>headerData(): 返回给定行或列的标头数据。</span></span>
<span class="line"><span>index(): 返回给定行和列的模型索引。</span></span>
<span class="line"><span>parent(): 返回给定索引的父索引。</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>2.QTableView</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>insertRows(): 插入行。</span></span>
<span class="line"><span>removeRows(): 删除行。</span></span>
<span class="line"><span>insertColumns(): 插入列。</span></span>
<span class="line"><span>removeColumns(): 删除列。</span></span>
<span class="line"><span>sort(): 对模型数据进行排序。</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>3.QListView 专用</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>insertRows(): 插入行。</span></span>
<span class="line"><span>removeRows(): 删除行。</span></span>
<span class="line"><span>sort(): 对模型数据进行排序。</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>4.QAbstractItemView：</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>setModel(): 关联数据模型。</span></span>
<span class="line"><span>setSelectionModel(): 关联选择模型。</span></span>
<span class="line"><span>setIndexWidget(): 在指定索引处设置自定义小部件。</span></span>
<span class="line"><span>currentIndex(): 返回当前选择的模型索引。</span></span>
<span class="line"><span>selectedIndexes(): 返回所有选定的模型索引。</span></span>
<span class="line"><span>scrollTo(): 滚动到指定索引处。</span></span>
<span class="line"><span>edit(): 编辑指定索引处的单元格。</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="item-widgets简单视图" tabindex="-1"><a class="header-anchor" href="#item-widgets简单视图"><span>Item Widgets简单视图</span></a></h1><p>QListWidget     List Widget     列表单元控件<br> QTreeWidget     Tree Widget     树形单元控件<br> QTableWidget     Table Widget     表格单元控件</p><p><strong>一、ListWidget控件</strong><br>     1.控件位置：Item Widget-&gt;ListWidget<br>     2.控件介绍：ListWidget继承自QListView类，基于Item的列表控件。<br>     3.控件属性设置选项：</p><p>（1）name：该控件对应源代码内的名称<br>         （2）font：设置该表格内部的字体<br>         （3）count：保持项目的数目<br>         （4）currentRow：保持当前项目的行<br>         （5）sortingEnabled：是否对item排序</p><p>4.常用成员函数：</p><p>（1）QListWidget：：QListWidget（QWidget *parent = 0）</p><p>构造父对象为parent的ListWidget</p><p>（2）void QListWidget：：addItem（QListWidgetItem *item）</p><p>添加项目item</p><p>（3）void QListWidget：：addItem（const QString &amp;label）</p><p>添加一个新的项目，在新添加的项目中添加label标签</p><p>（4）void QListWidget：：addItems（const QStringList &amp;labels）</p><p>添加一列项目</p><p>（5）void QListWidget：：clear（）[slot]</p><p>清除该ListWidget中的所有项目</p><p>（6）QListWidgetItem *QListWidget：：currentItem（）const</p><p>返回当前活动的项目</p><p>（7）void QListWidget：：editItem（QListWidgetItem *item）</p><p>如果项目item是可编辑的，开始编辑项目item</p><p>（8）QList&lt;QListWidgetItem *&gt;QListWidget：：findItems（const QString &amp;text，Qt：：MatchFlags flags）const</p><p>查找匹配字符串text的项目，并返回查找结果</p><p>（9）void QListWidget：：insertItem（int row，QListWidgetItem * item）</p><p>在行row处插入项目item</p><p>（10）void QListWidget：：insertItem（int row，const QString &amp;label）</p><p>这是一个重载函数，功能同（9），在行row处插入标签为label的新项目</p><p>（11）void QListWidget：：insertItem（int row，const QStringList &amp;labels）</p><p>在行row处插入一列项目</p><p>（12）QListWidgetItem *QListWidget：：item（int row）const</p><p>返回行row处的项目，如果行row处没有项目则返回0</p><p>（13）QListWidgetItem *QListWidget：：itemAt（const QPoint &amp;p）const</p><p>返回点p处的项目</p><p>（14）QListWidgetItem *QListWidget：：itemAt（int row，int y）const</p><p>返回坐标（x，y）处的项目</p><p>（15）QWidget *QListWidget：：itemWidget（QListWidgetItem *item）const</p><p>返回项目item处显示的控件</p><p>（16）QListWidgetItem *QListWidget：：takeItem（int row）</p><p>移除行row处的项目，并返回项目控件</p><p>（17）void QListWidget：：removeItemWidget（QListWidgetItem *item）</p><p>移除项目item处的控件</p><p>（18）int QListWidget：：row（const QListWidgetItem *item）cosnt</p><p>返回项目item所在的行</p><p>（19）QList&lt;QListWidgetItem*&gt; QListWidget：：selectedItems（）const</p><p>返回所有被选中的项目的控件</p><p>（20）void QListWidget：：setcurrentItem（QListWidgetItem *item）</p><p>设置项目item为当前项目</p><p>（21）void QListWidget：：setItemWidget（QListWidgetItem *item，QWidget *widget）</p><p>设置控件widget为项目item的显示控件</p><p>（22）void QListWidget：：setItemWidget（QListWidgetItem *item，QWidget *widget）</p><p>（23）void QListWidget：：sortItems（Qt：：SortOrder order = Qt：：AscendingOrder）</p><p>把项目按照order进行排序</p><p><strong>二、TreeWidget控件</strong><br>     1.控件位置：Item Widget-&gt;TreeWidget<br>     2.控件介绍：树形单元控件，继承自QTreeView类，是树形视图使用预定义的模型，他也是基于模型/视图结构的控件，为方便开发人员使用树形视图，可以使用这个控件来创建简单地树形结构列表<br>     3.控件属性设置选项：</p><p>（1）name：同上<br>         （2）font：同上<br>         （3）columnCount：保存该TreeWidget的列数</p><p>4.常用成员函数</p><p>（1）QTreeWidget：：QTreeWidget（QWidget *parent = 0）</p><p>构造一个父对象为parent的TreeWidget</p><p>（2）void QTreeWidget：：addTopLevelItem（QTreeWidgetItem * item）</p><p>在该TreeWidget中追加item为顶级项目</p><p>（3）void QTreeWidget：：addTopLevelItems（const QList&lt;QTreeWidgetItem*&gt; &amp;items）</p><p>把items中的项目作为顶级项目追加到该TreeWidget中</p><p>（4）void QTreeWidget：：clear（）[slot]</p><p>清除该TreeWidget中的所有项目</p><p>（5）void QTreeWidget：：collapseItem（const QTreeWidgetItem *item）[slot]</p><p>折叠项目item</p><p>（6）int QTreeWidget：：currentColumn（）const</p><p>返回当前活动列</p><p>（7）QTreeWidgetItem *QTreeWidget：：currentItem（）const</p><p>返回当前活动项目</p><p>（8）void QTreeWidget：：editItem（QTreeWidgetItem *item，int column = 0）</p><p>如果列column的item是可编辑的，开始编辑</p><p>（9）void QTreeWidget：：expandItem（const QTreeWidgetItem *item）[slot]</p><p>展开项目</p><p>（10）QList&lt;QTreeWidgetItem*&gt; QTreeWidget：：findItems（const QString &amp;text，Qt：：MatchFlags flags，int column = 0）const</p><p>查找匹配字符串的text的项目，并返回查找结果</p><p>（11）QTreeWidgetItem *QTreeWidget：：headerItem（）const</p><p>返回头项目</p><p>（12）QModelIndex QTreeWidget：：indexFromItem（QTreeWidgetItem *item，int column = 0）const [protected]</p><p>返回列column的项目item模型索引</p><p>（13）int QTreeWidget：：indexOfTopLevelItem（QTreeWidgetItem *item）const</p><p>返回顶级项目item的模型索引，如果item不存在返回-1</p><p>（14）int QTreeWidget：：sortColumn（）const<br>         返回排序的列</p><p>（15）void QTreeWidget：：sortItems（int column，Qt：：SortOrder order）</p><p>对列column的项目按照order进行排序</p><p>（16）QTreeWidgetItem *QTreeWidget：：itemAbove（const QTreeWidgetItem *item）const</p><p>返回item的上一个项目</p><p>（17）QTreeWidgetItem *QTreeWidget：：itemAt（const QPoint &amp;p） const</p><p>返回点p处的项目</p><p>（18）QTreeWidgetItem *QTreeWidget：：itemAt（int x，int y）const</p><p>返回坐标（x，y）处的项目</p><p>（19）void QTreeWidget：：setItemWidget（QTreeWidgetItem *item，int column，QWidget *widget）</p><p>设置控件widget为项目item的显示控件，项目item在列column中</p><p>（20）QTreeWidgetItem *QTreeWidget：：itemBelow（const QTreeWidgetItem *item）const</p><p>返回item的下一个项目</p><p>（21）QWidget *QTreeWidget：：itemWidget（QTreeWidgetItem *item，int column）const</p><p>返回列column中的项目item显示控件</p><p>（22）void QTreeWidget：：removeItemWidget（QTreeWidgetItem *item，int column）</p><p>移除列column中的项目item的显示控件</p><p>（23）QList&lt;QTreeWidgetItem *&gt; QTreeWidget：：selectItems（）const</p><p>返回所有选中状态的项目</p><p>（24）void QTreeWidget：：setCurrentItem（QTreeWidgetItem *item）</p><p>设置item为当前项目</p><p>（25）void QTreeWidget：：setCurrentItem（QTreeWidgetItem *item，int column）</p><p>设置列column的项目item为当前项目</p><p>（26）void QTreeWidget；：setHeaderItem（QTreeWidgetItem *item）</p><p>设置item为该TreeWidget的头项目</p><p>（27）void QTreeWidget：：setHeaderLabel（const QString &amp;label）</p><p>设置label为头标题</p><p>（28）QTreeWidgetItem *QTreeWidget：：topLevelItem（int index）cosnt</p><p>返回所有index的顶级项目</p><p><strong>三、TableWidget控件</strong><br>     1.控件位置：Item Widget-&gt;Table Widget<br>     2.控件介绍：表格单元控件<br>     3.控件属性设置选项：</p><p>（1）name：同上<br>         （2）font：同上<br>         （3）columnCount：保存列的数目<br>         （4）rowCount：保存行的数目</p><p>4.常用成员函数</p><p>（1）QTableWidget：：QTableWidget（QWidget * parent = 0）</p><p>构造一个父对象为parent的TableWidget</p><p>（2）QTableWidget：：QTableWidget（int rows，int columns，QWidget *parent = 0）</p><p>构造一个rows行，columns列，父对象为parent的TableWidget控件</p><p>（3）QWidget *QTableWidget：：cellWidget（int row，int column）const</p><p>返回行row，列column的单元格处的控件</p><p>（4）void QTableWidget：：clear（）[slot]</p><p>删除该TreeWidget中的所有项目</p><p>（5）void QTableWidget：：clearContents（）[slot]</p><p>删除该TreeWidget中除了header外的所有项目</p><p>（6）int QTableWidget：：column（const QTableWidgetItem *item）const</p><p>返回项目item所在的列</p><p>（7）int QTableWidget：：currentColumn（）const</p><p>返回当前活动的列</p><p>（8）QTableWidgetItem *QTableWidget：：currentItem（）const</p><p>返回当前活动的项目</p><p>（9）int QTableWidget：：currentRow（）const</p><p>返回当前活动的行</p><p>（10）void QTableWidget：：editItem（QTableWidgetItem *item）</p><p>如果item是可编辑的，开始编辑item</p><p>（11）QList&lt;QTableWidgetItem *&gt; QTableWidget：：findItems（const QString &amp;text，Qt：：MatchFlags flags）const</p><p>查找匹配字符串text的项目，并返回查找结果</p><p>（12）void QTableWidget：：insertColumn（int column）[slot]</p><p>在列column处插入新列</p><p>（13）void QTableWidget：：insertRow（int row）[slot]</p><p>在行row处插入新行</p><p>（14）QTableWidgetItem *QTableWidget：：item（int row，int column）const</p><p>返回行row、列column处的项目</p><p>（15）QTableWidgetItem *QTableWidget：：itemAt（const QPoint &amp;point）const</p><p>返回点point处的项目</p><p>（16）QTableWidgetItem *QTableWidget：：itemAt（int ax，int ay）const</p><p>返回坐标（ax，ay）处的项目</p><p>（17）void QTableWidget：：removeCellWidget（int row，int column）</p><p>移除行row、列column单元格处的显示控件</p><p>（18）void QTableWidget：：removeColumn（int column）[slot]</p><p>移除列column</p><p>（19）void QTableWidget：：removerRow（int row）[slot]</p><p>移除行row</p><p>（20）int QTableWidget：：row（const QTableWidgetItem *item）cosnt</p><p>返回item的行</p><p>（21）QList&lt;QTableWidgetItem *&gt; QTableWidget：：selectedItems（）</p><p>返回所有选中状态的项目</p><p>（22）void QTableWidget：：setCellWidget（int row，int column，QWidget *widget）</p><p>设置行row、列column处的显示控件为widget。</p><p>（23）void QTableWidget：：setCurrentCell（int row，int column）</p><p>设置行row，列column处的单元格为当前活动单元格</p><p>（24）void QTableWidget：：setCurrentItem（QTableWidgetItem *item）</p><p>设置项目item为当前活动项目</p><p>（25）void QTableWidget：：setHorizontalHeaderItem（int column，QTableWidgetItem *item）</p><p>设置项目item为列column的水平头项目，功能同setVerticalHeaderItem（）</p><p>（26）void QTableWidget：：setHorizontalHeaderLabels（const QStringList *labels）</p><p>设置水平标题为labels，功能同setVerticalHeaderLabels（）</p><p>（27）void QTableWidget：：setItem（int row，int column，QTableWidgetItem *item）</p><p>设置行row、列column的单元格的项目为item</p><p>（28）void QTableWidget：：sortItems（int column，Qt：：SortOrder order = Qt：：AscendingOrder）</p><p>对列column按照order进行排序</p><p>（29）QTableWidgetItem *QTableWidget：：takeHorizonalHeaderItem（int column）</p><p>移除列column的水平头项目，功能同takeVerticalHeaderItem（）</p><p>（30）QTableWidgetItem *QTableWidget：：takeItem（int row，int column）</p><p>移除行row、列column单元格处的项目</p><p>（31）QTableWidgetItem *QTableWidget：：verticalHeaderItem（int row）const</p><p>返回行row的垂直头项目</p>`,184)]))}const l=t(n,[["render",d]]),m=JSON.parse('{"path":"/cpp/qt/14/","title":"14 Item Views视图","lang":"zh-CN","frontmatter":{"title":"14 Item Views视图","createTime":"2025/06/22 10:43:10","permalink":"/cpp/qt/14/"},"readingTime":{"minutes":8.1,"words":2430},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/Qt/14 Item Views视图.md","headers":[]}');export{l as comp,m as data};
